23	QEMU_PLUGIN_EXPORT int qemu_plugin_version = QEMU_PLUGIN_VERSION;
24	
25	typedef struct {
26	    struct qemu_plugin_register *gpr[32];
27	    struct qemu_plugin_register *fpr[32];
28	    struct qemu_plugin_register *pc;
29	
30	    // M-mode CSRs as exposed by QEMU's gdbstub csr feature.
31	    struct qemu_plugin_register *mstatus;
32	    struct qemu_plugin_register *mepc;
33	    struct qemu_plugin_register *mtvec;
34	    struct qemu_plugin_register *mcause;
35	    struct qemu_plugin_register *mtval;
36	    struct qemu_plugin_register *mscratch;
37	    struct qemu_plugin_register *medeleg;
38	    struct qemu_plugin_register *mideleg;
39	    struct qemu_plugin_register *mip;
40	    struct qemu_plugin_register *mie;
41	    struct qemu_plugin_register *mcycle;
42	    struct qemu_plugin_register *minstret;
43	    struct qemu_plugin_register *satp;
44	
45	    struct qemu_plugin_register *pmpcfg[HYBRID_PMP_CFG_NUM];
46	    struct qemu_plugin_register *pmpaddr[HYBRID_PMP_ADDR_NUM];
47	
48	    struct qemu_plugin_register *vstart;
49	    struct qemu_plugin_register *vtype;
50	    struct qemu_plugin_register *vl;
51	    struct qemu_plugin_register *vlenb;
52	    struct qemu_plugin_register *vreg[32];
53	} VcpuRegs;
54	
55	static struct qemu_plugin_scoreboard *vcpu_state;
56	static char *outfile_path;
57	
58	// PC-trigger mode: when enter_pc_arg is non-zero (set via plugin arg
59	// `enter_pc=0x...`), the CSR-insn matcher is bypassed entirely and the
60	// drain callback is registered only for instructions whose vaddr equals
61	// enter_pc_arg. The kind reported on the drain is HYBRID_HANDOFF_ENTER
62	// (entry into vsim), matching CSR-mode `csrwi 0x7C0, 0` semantics.
63	static uint64_t enter_pc_arg;
64	static int pc_mode;
65	
66	static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
67	{
68	    for (guint i = 0; i < regs->len; i++) {
69	        qemu_plugin_reg_descriptor *rd =
70	            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
71	        if (g_ascii_strcasecmp(rd->name, name) == 0) {
72	            return rd->handle;
73	        }
74	    }
75	    return NULL;
76	}
77	
78	// Lazily resolves register handles. The plugin's vcpu_init runs before
79	// QEMU has registered the dynamic gdb coprocessors (FPU, virtual, csr,
80	// vector), so qemu_plugin_get_registers() returns only the 33 core CPU
81	// regs at that moment. By the time the entry trigger fires, all dynamic
82	// features are registered and a fresh call returns the full list.
83	static void resolve_handles(VcpuRegs *v)
84	{
85	    g_autoptr(GArray) regs = qemu_plugin_get_registers();
86	    for (int i = 0; i < 32; i++) {
87	        v->gpr[i] = find_reg(regs, hybrid_gpr_names[i]);
88	        v->fpr[i] = find_reg(regs, hybrid_fpr_names[i]);
89	    }
90	    v->pc = find_reg(regs, "pc");
91	
92	    v->mstatus  = find_reg(regs, "mstatus");
93	    v->mepc     = find_reg(regs, "mepc");
94	    v->mtvec    = find_reg(regs, "mtvec");
95	    v->mcause   = find_reg(regs, "mcause");
96	    v->mtval    = find_reg(regs, "mtval");
97	    v->mscratch = find_reg(regs, "mscratch");
98	    v->medeleg  = find_reg(regs, "medeleg");
99	    v->mideleg  = find_reg(regs, "mideleg");
100	    v->mip      = find_reg(regs, "mip");
101	    v->mie      = find_reg(regs, "mie");
102	    v->mcycle   = find_reg(regs, "mcycle");
103	    v->minstret = find_reg(regs, "minstret");
104	    v->satp     = find_reg(regs, "satp");
105	
106	    char buf[16];
107	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++) {
108	        g_snprintf(buf, sizeof(buf), "pmpcfg%d", i);
109	        v->pmpcfg[i] = find_reg(regs, buf);
110	    }
111	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++) {
112	        g_snprintf(buf, sizeof(buf), "pmpaddr%d", i);
113	        v->pmpaddr[i] = find_reg(regs, buf);
114	    }
115	
116	    v->vstart = find_reg(regs, "vstart");
117	    v->vtype  = find_reg(regs, "vtype");
118	    v->vl     = find_reg(regs, "vl");
119	    v->vlenb  = find_reg(regs, "vlenb");
120	    for (int i = 0; i < 32; i++) {
121	        g_snprintf(buf, sizeof(buf), "v%d", i);
122	        v->vreg[i] = find_reg(regs, buf);
123	    }
124	}
125	
126	static uint64_t read_reg64(struct qemu_plugin_register *h)
127	{
128	    if (!h) return 0;
129	    g_autoptr(GByteArray) buf = g_byte_array_new();
130	    int sz = qemu_plugin_read_register(h, buf);
131	    if (sz <= 0) return 0;
132	    uint64_t v = 0;
133	    memcpy(&v, buf->data, sz < 8 ? (size_t) sz : 8);
134	    return v;
135	}
136	
137	// Reads up to `dst_max` bytes from a register handle. Returns the byte
138	// count written (0 on failure or NULL handle). Used for vector regs whose
139	// width = vlenb bytes.
140	static size_t read_reg_bytes(struct qemu_plugin_register *h,
141	                             uint8_t *dst, size_t dst_max)
142	{
143	    if (!h || dst_max == 0) return 0;
144	    g_autoptr(GByteArray) buf = g_byte_array_new();
145	    int sz = qemu_plugin_read_register(h, buf);
146	    if (sz <= 0) return 0;
147	    size_t n = (size_t) sz < dst_max ? (size_t) sz : dst_max;
148	    memcpy(dst, buf->data, n);
149	    return n;
150	}
151	
152	// Atomic on POSIX: write to .tmp, fsync, rename.
153	static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
154	{
155	    char tmp[PATH_MAX];
156	    g_snprintf(tmp, sizeof(tmp), "%s.tmp.%d", path, (int) getpid());
157	    int fd = open(tmp, O_WRONLY | O_CREAT | O_TRUNC, 0600);
158	    if (fd < 0) {
159	        perror("hybrid_handoff: open tmp");
160	        return -1;
161	    }
162	    ssize_t want = (ssize_t) sizeof(*s);
163	    ssize_t got = write(fd, s, sizeof(*s));
164	    if (got != want) {
165	        perror("hybrid_handoff: write");
166	        close(fd);
167	        unlink(tmp);
168	        return -1;
169	    }
170	    fsync(fd);
171	    close(fd);
172	    if (rename(tmp, path) != 0) {
173	        perror("hybrid_handoff: rename");
174	        unlink(tmp);
175	        return -1;
176	    }
177	    return 0;
178	}
179	
180	static void on_handoff(unsigned int vcpu_idx, void *udata)
181	{
182	    hybrid_handoff_kind kind = (hybrid_handoff_kind) (uintptr_t) udata;
183	    if (kind != HYBRID_HANDOFF_ENTER) return;
184	
185	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
186	    resolve_handles(v);
187	    struct hybrid_state_v1 s = {0};
188	    s.magic   = HYBRID_STATE_MAGIC;
189	    s.version = HYBRID_STATE_VERSION;
190	    s.flags   = HYBRID_FLAG_RV64;
191	    s.hart_id = vcpu_idx;
192	    s.priv    = 3;
193	    s.pc      = read_reg64(v->pc);
194	    for (int i = 0; i < 32; i++) s.gpr[i] = read_reg64(v->gpr[i]);
195	
196	    // Floating-point: only set FP flag if at least one handle was bound,
197	    // i.e. QEMU advertised the FPU feature (D extension).
198	    int has_fp = 0;
199	    for (int i = 0; i < 32; i++) {
200	        s.fpr[i] = read_reg64(v->fpr[i]);
201	        if (v->fpr[i]) has_fp = 1;
202	    }
203	    if (has_fp) s.flags |= HYBRID_FLAG_FP;
204	
205	    s.mstatus  = read_reg64(v->mstatus);
206	    s.mepc     = read_reg64(v->mepc);
207	    s.mtvec    = read_reg64(v->mtvec);
208	    s.mcause   = read_reg64(v->mcause);
209	    s.mtval    = read_reg64(v->mtval);
210	    s.mscratch = read_reg64(v->mscratch);
211	    s.medeleg  = read_reg64(v->medeleg);
212	    s.mideleg  = read_reg64(v->mideleg);
213	    s.mip      = read_reg64(v->mip);
214	    s.mie      = read_reg64(v->mie);
215	    s.mcycle   = read_reg64(v->mcycle);
216	    s.minstret = read_reg64(v->minstret);
217	    s.satp     = read_reg64(v->satp);
218	
219	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++)
220	        s.pmpcfg[i] = read_reg64(v->pmpcfg[i]);
221	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++)
222	        s.pmpaddr[i] = read_reg64(v->pmpaddr[i]);
223	
224	    // Vector: only set V flag if QEMU advertised the V extension. vlenb
225	    // bounds the per-register byte count copied into vreg[].
226	    s.vstart = read_reg64(v->vstart);
227	    s.vtype  = read_reg64(v->vtype);
228	    s.vl     = read_reg64(v->vl);
229	    s.vlenb  = read_reg64(v->vlenb);
230	    if (v->vlenb && s.vlenb > 0) {
231	        s.flags |= HYBRID_FLAG_V;
232	        size_t bytes = s.vlenb < HYBRID_VLEN_BYTES_MAX
233	                     ? (size_t) s.vlenb
234	                     : (size_t) HYBRID_VLEN_BYTES_MAX;
235	        for (int i = 0; i < 32; i++)
236	            (void) read_reg_bytes(v->vreg[i],
237	                                  &s.vreg[(size_t) i * HYBRID_VLEN_BYTES_MAX],
238	                                  bytes);
239	    }
240	
241	    if (write_state_atomic(&s, outfile_path) != 0) {
242	        fprintf(stderr, "hybrid_handoff: failed to write state file\n");
243	        exit(2);
244	    }
245	    fprintf(stderr,
246	            "hybrid_handoff: drained state to %s (pc=%#" PRIx64 "), exiting\n",
247	            outfile_path, s.pc);
248	    exit(0);
249	}
250	
251	static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
252	{
253	    (void) id;
254	    size_t n = qemu_plugin_tb_n_insns(tb);
255	    for (size_t i = 0; i < n; i++) {
256	        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);
257	
258	        if (pc_mode) {
259	            // PC-trigger mode: vaddr-only match, no insn-data inspection,
260	            // no size guard (a future fixture might park enter_pc on a
261	            // compressed insn).
262	            if (qemu_plugin_insn_vaddr(insn) != enter_pc_arg) continue;
263	            qemu_plugin_register_vcpu_insn_exec_cb(
264	                insn, on_handoff, QEMU_PLUGIN_CB_R_REGS,
265	                (void *) (uintptr_t) HYBRID_HANDOFF_ENTER);
266	            continue;
267	        }
268	
269	        // CSR-trigger mode (default).
270	        size_t sz = qemu_plugin_insn_size(insn);
271	        if (sz != 4) continue;
272	        uint32_t raw = 0;
273	        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
274	            continue;
275	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
276	        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
277	        qemu_plugin_register_vcpu_insn_exec_cb(
278	            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS,
279	            (void *) (uintptr_t) kind);
280	    }
281	}
282	
283	QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
284	                                           const qemu_info_t *info,
285	                                           int argc, char **argv)
286	{
287	    (void) info;
288	    for (int i = 0; i < argc; i++) {
289	        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
290	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
291	            outfile_path = g_strdup(tok[1]);
292	        } else if (g_strcmp0(tok[0], "enter_pc") == 0 && tok[1]) {
293	            char *endp = NULL;
294	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
295	            if (!endp || *endp != '\0') {
296	                fprintf(stderr, "hybrid_handoff: invalid enter_pc=%s\n",
297	                        tok[1]);
298	                return -1;
299	            }
300	            enter_pc_arg = (uint64_t) v;
301	            pc_mode = 1;
302	        } else {
303	            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
304	            return -1;
305	        }
306	    }
307	    if (!outfile_path) {
308	        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
309	        return -1;
310	    }
311	    if (pc_mode) {
312	        fprintf(stderr,
313	                "hybrid_handoff: PC-mode enter=0x%" PRIx64 "\n",
314	                enter_pc_arg);
315	    }
316	
317	    vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
318	    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
319	    return 0;
320	}
