1	#pragma once
2	
3	#include "hybrid/abstract_command.hpp"
4	#include "hybrid/dmi_poll.hpp"
5	#include "hybrid/state_abi.h"
6	
7	#include <cstdint>
8	#include <stdexcept>
9	
10	namespace hybrid {
11	
12	struct DmiBus
13	{
14	  virtual ~DmiBus() = default;
15	  virtual void write(uint8_t reg, uint32_t value) = 0;
16	  virtual auto read(uint8_t reg) -> uint32_t = 0;
17	};
18	
19	class ResumeDriver
20	{
21	public:
22	  static constexpr uint8_t kData0      = 0x04;
23	  static constexpr uint8_t kData1      = 0x05;
24	  static constexpr uint8_t kDmcontrol  = 0x10;
25	  static constexpr uint8_t kDmstatus   = 0x11;
26	  static constexpr uint8_t kAbstractcs = 0x16;
27	  static constexpr uint8_t kCommand    = 0x17;
28	
29	  static constexpr uint16_t kCsrDpc = 0x7B1;
30	
31	  static constexpr uint32_t kDmcontrolDmactive  = 1u << 0;
32	  static constexpr uint32_t kDmcontrolResumereq = 1u << 30;
33	  static constexpr uint32_t kDmcontrolHaltreq   = 1u << 31;
34	
35	  static constexpr uint32_t kDmstatusAllhalted    = 1u << 9;
36	  static constexpr uint32_t kDmstatusAllresumeack = 1u << 17;
37	
38	  static constexpr uint32_t kAbstractcsBusy        = 1u << 12;
39	  static constexpr uint32_t kAbstractcsCmderrMask  = 0x7u << 8;
40	
41	  static constexpr unsigned kPollIterations = kDmiPollIterations;
42	
43	  explicit ResumeDriver(DmiBus& bus)
44	      : bus_{bus}
45	  {}
46	
47	  void resume(const hybrid_state_v1& state)
48	  {
49	    if (state.magic != HYBRID_STATE_MAGIC)
50	      throw std::runtime_error("ResumeDriver::resume: bad magic");
51	    if (state.version != HYBRID_STATE_VERSION)
52	      throw std::runtime_error("ResumeDriver::resume: unsupported version");
53	
54	    // dmactive must transition 0->1 in its own write before any other
55	    // DMCONTROL bit is honored (RISC-V Debug Spec).
56	    bus_.write(kDmcontrol, kDmcontrolDmactive);
57	    request_halt();
58	    poll_until_set(bus_, kDmstatus, kDmstatusAllhalted, "ResumeDriver halt");
59	
60	    // Only GPRs + DPC; FP/CSR/V are merged at drain time.
61	    for (uint16_t i = 1; i < 32; ++i)
62	      write_64bit_register(regno_gpr(i), state.gpr[i]);
63	    write_64bit_register(regno_csr(kCsrDpc), state.pc);
64	
65	    clear_cmderr_if_set();
66	    request_resume();
67	    poll_until_set(bus_, kDmstatus, kDmstatusAllresumeack,
68	                   "ResumeDriver resume");
69	  }
70	
71	private:
72	  void request_halt()
73	  {
74	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolHaltreq);
75	  }
76	
77	  void request_resume()
78	  {
79	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolResumereq);
80	  }
81	
82	  void write_64bit_register(uint16_t regno, uint64_t value)
83	  {
84	    bus_.write(kData0, uint32_t(value & 0xffffffffu));
85	    bus_.write(kData1, uint32_t((value >> 32) & 0xffffffffu));
86	    bus_.write(kCommand,
87	               access_register_command(regno, AarSize::Bits64, /*write=*/true));
88	    poll_until_clear(bus_, kAbstractcs, kAbstractcsBusy,
89	                     "ResumeDriver write_register");
90	  }
91	
92	  // abstractcs.cmderr is sticky per the Debug Spec - a subsequent command
93	  // is rejected until the bits are W1C-cleared. We tolerate per-register
94	  // failures (e.g. unimplemented FPR/CSR Abstract access) by clearing the
95	  // error before resuming so the hart isn't left in a stuck state.
96	  void clear_cmderr_if_set()
97	  {
98	    const auto status = bus_.read(kAbstractcs);
99	    if ((status & kAbstractcsCmderrMask) != 0u)
100	      bus_.write(kAbstractcs, kAbstractcsCmderrMask);
101	  }
102	
103	  DmiBus& bus_;
104	};
