165	// Fetches a qXfer:features:read annex in full, looping while the stub
166	// answers with the 'm' (more) marker. QEMU's RISC-V CSR XML is ~6 KB and
167	// PacketSize is typically 1000 bytes, so several iterations are normal.
168	inline auto fetch_feature_xml(gdbstub::Session& sess, const std::string& annex)
169	  -> std::string
170	{
171	  std::string accum;
172	  std::size_t offset = 0;
173	  // Use a chunk size below the QEMU default PacketSize=1000. Asking for
174	  // 0x100 keeps each frame well under the wire limit even after the 'm'
175	  // marker and packet framing overhead.
176	  constexpr std::size_t kChunk = 0x100;
177	  while (true) {
178	    char buf[64];
179	    std::snprintf(buf, sizeof(buf), ":%zx,%zx", offset, kChunk);
180	    auto body = sess.send_command("qXfer:features:read:" + annex + buf);
181	    if (body.empty())
182	      throw std::runtime_error("qXfer empty reply for " + annex);
183	    const char marker = body.front();
184	    if (marker != 'l' && marker != 'm')
185	      throw std::runtime_error("qXfer non-l/m reply for " + annex + ": "
186	                               + std::string{marker});
187	    accum.append(body.substr(1));
188	    if (marker == 'l') return accum;
189	    offset += body.size() - 1;
190	  }
191	}
