207	// Sends one P packet whose body is built by the supplied encoder. A
208	// missing register name is silently skipped: not every QEMU build
209	// advertises every PMP slot or extension CSR, so absence isn't fatal.
210	template<class Encoder>
211	inline void try_write_named(gdbstub::Session& sess,
212	                            const gdbstub::RegMap& map,
213	                            const std::string& name,
214	                            Encoder&& encoder)
215	{
216	  const auto reg_num = map.find(name);
217	  if (!reg_num) return;
218	  auto reply = sess.send_command(encoder(*reg_num));
219	  if (reply != "OK")
220	    throw std::runtime_error("gdbstub: P packet for " + name + " replied "
221	                             + reply);
222	}
