224	inline void try_write_named_u64(gdbstub::Session& sess,
225	                                const gdbstub::RegMap& map,
226	                                const std::string& name,
227	                                uint64_t value)
228	{
229	  try_write_named(sess, map, name, [&](unsigned r) {
230	    return gdbstub::encode_p_body(r, value);
231	  });
232	}
