330	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
331	// status (or 128 + signal for abnormal termination).
332	inline auto run_qemu_handback(const std::string& qemu_binary,
333	                              const std::string& elf_path,
334	                              const hybrid_state_v1& state,
335	                              const std::string& shared_mem_path = {},
336	                              uint64_t shared_mem_size = 0) -> int
337	{
338	  const auto port = detail::pick_free_port();
339	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
340	               qemu_binary, port);
341	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port,
342	                                       shared_mem_path, shared_mem_size);
343	
344	  try {
345	    restore_state_via_gdbstub(port, state, pid);
346	  } catch (const detail::ChildExitedDuringConnect& d) {
347	    return d.status;
348	  } catch (...) {
349	    ::kill(pid, SIGKILL);
350	    int wstat = 0;
351	    ::waitpid(pid, &wstat, 0);
352	    throw;
353	  }
354	
355	  int wstat = 0;
356	  if (::waitpid(pid, &wstat, 0) < 0)
357	    throw std::runtime_error(std::string{"waitpid: "}
358	                             + std::strerror(errno));
359	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
360	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
361	  return -1;
362	}
