67	TEST_CASE("byte-level roundtrip via memcpy preserves all fields")
68	{
69	  hybrid_state_v1 src{};
70	  src.magic = HYBRID_STATE_MAGIC;
71	  src.version = HYBRID_STATE_VERSION;
72	  src.flags = HYBRID_FLAG_RV64 | HYBRID_FLAG_FP | HYBRID_FLAG_V;
73	  src.hart_id = 1;
74	  src.pc = 0x80001234ULL;
75	  src.priv = 3;  // M-mode
76	
77	  for (int i = 0; i < 32; ++i) {
78	    src.gpr[i] = 0xCAFE0000ULL + i;
79	    src.fpr[i] = 0xF00D0000ULL + i;
80	  }
81	  src.mstatus = 0xa00040080ULL;
82	  src.mepc    = 0x80002000ULL;
83	  src.mtvec   = 0x80000000ULL;
84	  src.satp    = 0x8000000000080000ULL;
85	  src.vstart  = 0;
86	  src.vtype   = 0xc0;
87	  src.vl      = 4;
