21	namespace hybrid::gdbstub
22	{
23	
24	inline auto compute_checksum(std::string_view body) -> uint8_t
25	{
26	  unsigned sum = 0;
27	  for (char c : body) sum += static_cast<unsigned char>(c);
28	  return static_cast<uint8_t>(sum & 0xFFu);
29	}
30	
31	namespace detail
32	{
33	
34	inline auto hex_nybble(unsigned v) -> char
35	{
36	  return static_cast<char>(v < 10 ? '0' + v : 'a' + (v - 10));
37	}
38	
39	inline void append_hex_byte(std::string& out, uint8_t b)
40	{
41	  out.push_back(hex_nybble((b >> 4) & 0xFu));
42	  out.push_back(hex_nybble(b & 0xFu));
43	}
44	
45	inline auto from_hex(char c) -> std::optional<unsigned>
46	{
47	  if (c >= '0' && c <= '9') return static_cast<unsigned>(c - '0');
48	  if (c >= 'a' && c <= 'f') return static_cast<unsigned>(c - 'a' + 10);
49	  if (c >= 'A' && c <= 'F') return static_cast<unsigned>(c - 'A' + 10);
50	  return std::nullopt;
51	}
52	
53	}  // namespace detail
54	
55	inline auto encode_packet(std::string_view body) -> std::string
56	{
57	  std::string out;
58	  out.reserve(body.size() + 4);
59	  out.push_back('$');
60	  out.append(body);
61	  out.push_back('#');
62	  detail::append_hex_byte(out, compute_checksum(body));
63	  return out;
64	}
65	
66	namespace detail
67	{
68	
69	// Emits a register number in the minimum number of hex nibbles. CSR-feature
70	// regnums in QEMU's RISC-V gdbstub run up to ~3000, so 2-nibble encodings
71	// silently truncate and clobber a low-numbered register.
72	inline void append_reg_num_hex(std::string& out, unsigned reg_num)
73	{
74	  if (reg_num == 0) {
75	    out.push_back('0');
76	    return;
77	  }
78	  unsigned shift = 0;
79	  unsigned tmp   = reg_num;
80	  while (tmp >= 16) { tmp >>= 4; shift += 4; }
81	  while (true) {
82	    out.push_back(hex_nybble((reg_num >> shift) & 0xFu));
83	    if (shift == 0) break;
84	    shift -= 4;
85	  }
86	}
87	
88	}  // namespace detail
89	
90	// Body of a `P<reg-hex>=<value-bytes-le-hex>` packet (no $...# framing).
91	// reg is the GDB register number (0..31 for GPR, 32 for pc on RV64, 3-digit
92	// regnums for CSR-feature entries). value is encoded as 8 little-endian bytes.
93	inline auto encode_p_body(unsigned reg_num, uint64_t value) -> std::string
94	{
95	  std::string body;
96	  body.push_back('P');
97	  detail::append_reg_num_hex(body, reg_num);
98	  body.push_back('=');
99	  for (unsigned i = 0; i < 8; ++i) {
100	    detail::append_hex_byte(body, static_cast<uint8_t>(value & 0xFFu));

100	    detail::append_hex_byte(body, static_cast<uint8_t>(value & 0xFFu));
101	    value >>= 8;
102	  }
103	  return body;
104	}
105	
106	inline auto encode_p_packet(unsigned reg_num, uint64_t value) -> std::string
107	{
108	  return encode_packet(encode_p_body(reg_num, value));
109	}
110	
111	// `P<reg>=<bytes-le-hex>` body for arbitrary-width payloads (e.g. vector
112	// regs whose width = vlenb bytes).
113	inline auto encode_p_body_bytes(unsigned reg_num,
114	                                const uint8_t* bytes,
115	                                std::size_t n) -> std::string
116	{
117	  std::string body;
118	  body.reserve(4 + n * 2);
119	  body.push_back('P');
120	  detail::append_reg_num_hex(body, reg_num);
121	  body.push_back('=');
122	  for (std::size_t i = 0; i < n; ++i) detail::append_hex_byte(body, bytes[i]);
123	  return body;
124	}
125	
126	inline auto encode_continue() -> std::string
127	{
128	  return encode_packet("c");
129	}
130	
131	// Parses one $body#cksum frame and returns the body iff the checksum matches.
132	inline auto parse_packet(std::string_view raw) -> std::optional<std::string>
133	{
134	  if (raw.size() < 4 || raw.front() != '$') return std::nullopt;
135	  const auto hash = raw.find('#');
136	  if (hash == std::string_view::npos) return std::nullopt;
137	  if (raw.size() < hash + 3) return std::nullopt;
138	
139	  const auto body = raw.substr(1, hash - 1);
140	  const auto cs_hi = detail::from_hex(raw[hash + 1]);
141	  const auto cs_lo = detail::from_hex(raw[hash + 2]);
142	  if (!cs_hi || !cs_lo) return std::nullopt;
143	
144	  const auto expected = static_cast<uint8_t>((*cs_hi << 4) | *cs_lo);
145	  if (expected != compute_checksum(body)) return std::nullopt;
146	
147	  return std::string{body};
148	}
149	
150	// Map from gdb register name (e.g. "mstatus", "ft0") -> packet register
151	// number used in `P<reg>=...` and `g`/`G`. Built by walking target.xml +
152	// each `<xi:include>` annex.
153	class RegMap
154	{
155	public:
156	  void insert(std::string name, unsigned reg_num)
157	  {
158	    table_.emplace(std::move(name), reg_num);
159	  }
160	
161	  auto find(const std::string& name) const -> std::optional<unsigned>
162	  {
163	    const auto it = table_.find(name);
164	    if (it == table_.end()) return std::nullopt;
165	    return it->second;
166	  }
167	
168	  auto size() const -> std::size_t { return table_.size(); }
169	
170	private:
171	  std::unordered_map<std::string, unsigned> table_;
172	};
173	
174	// Extracts the value of an attribute from one XML element start tag.
175	// `tag_start` points at the '<' of the tag; the search runs until the
176	// matching '>' or the end of the string.
177	inline auto extract_attr(std::string_view xml,
178	                         std::size_t tag_start,
179	                         std::string_view name) -> std::optional<std::string>
180	{
181	  const auto end = xml.find('>', tag_start);
182	  if (end == std::string_view::npos) return std::nullopt;
183	  const auto window = xml.substr(tag_start, end - tag_start);
184	  std::string needle{name};
185	  needle.append("=\"");
186	  const auto k = window.find(needle);
187	  if (k == std::string_view::npos) return std::nullopt;
188	  const auto v_begin = k + needle.size();
189	  const auto v_end   = window.find('"', v_begin);
190	  if (v_end == std::string_view::npos) return std::nullopt;
191	  return std::string{window.substr(v_begin, v_end - v_begin)};
192	}
193	
194	// Walks a single feature XML body (the contents of one annex), extracting
195	// `<reg name="X" .../>` entries into the map. `next_unnumbered` is updated
196	// with the cumulative count of regs seen across all features so far; an
197	// explicit `regnum="N"` attribute overrides the counter for that one entry
198	// without changing the running total (QEMU's CSR feature uses sparse
199	// regnums, so each subsequent unnumbered entry would be ill-defined - in
200	// practice the CSR feature is the last one parsed).
201	inline void parse_feature_xml(std::string_view xml,
202	                              RegMap& map,
203	                              unsigned& next_unnumbered)
204	{
205	  std::size_t pos = 0;
206	  while (true) {
207	    const auto p = xml.find("<reg ", pos);
208	    if (p == std::string_view::npos) break;
209	    pos = p + 5;
210	    const auto name   = extract_attr(xml, p, "name");
211	    const auto regnum = extract_attr(xml, p, "regnum");
212	    if (!name) continue;
213	    unsigned id = next_unnumbered;
214	    if (regnum) {
215	      try {
216	        id = static_cast<unsigned>(std::stoul(*regnum));
217	      } catch (...) {
218	        id = next_unnumbered++;
219	      }
220	    } else {
221	      ++next_unnumbered;
222	    }
223	    map.insert(*name, id);
224	  }
225	}
226	
227	// Pulls each `<xi:include href="X"/>` href out of target.xml in declaration
228	// order. The order is significant: each annex extends the cumulative
229	// register-number counter from where the previous feature left off.
230	inline auto parse_target_xml(std::string_view xml) -> std::vector<std::string>
231	{
232	  std::vector<std::string> annexes;
233	  std::size_t pos = 0;
234	  while (true) {
235	    const auto p = xml.find("<xi:include", pos);
236	    if (p == std::string_view::npos) break;
237	    if (auto href = extract_attr(xml, p, "href")) annexes.push_back(*href);
238	    pos = p + 11;
239	  }
240	  return annexes;
241	}
